import{_ as e,a as t,b as n,c as i,d}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as o}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as r,o as l,c as s,a2 as u}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Other/ocr.md","filePath":"id-ID/Other/ocr.md","lastUpdated":1781962217000}'),c={name:"id-ID/Other/ocr.md"};function k(p,a,g,h,m,b){return l(),s("div",null,[...a[0]||(a[0]=[u('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR mengekstrak teks dari gambar, hasil scan, dan screenshot dokumen.</p><p>Setelah pengenalan selesai, Anda bisa menyalin hasilnya, mengekspornya sebagai <code>Markdown</code>, <code>PDF</code>, atau <code>Word</code>, atau mengemas beberapa format sekaligus untuk diunduh.</p><h2 id="yang-bisa-dilakukan-ocr" tabindex="-1">Yang Bisa Dilakukan OCR <a class="header-anchor" href="#yang-bisa-dilakukan-ocr" aria-label="Permalink to &quot;Yang Bisa Dilakukan OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fitur</th><th>Keterangan</th></tr></thead><tbody><tr><td>Pengenalan teks gambar</td><td>Mengekstrak teks dari gambar, screenshot, dan scan.</td></tr><tr><td>Pengenalan layout dokumen</td><td>Lebih cocok untuk tabel, rumus, cap, dan layout campuran teks-gambar.</td></tr><tr><td>Beberapa layanan</td><td>Mendukung Baidu PaddleOCR, Microsoft Azure Vision, dan Google Vision.</td></tr><tr><td>Menyalin hasil</td><td>Menyalin teks hasil pengenalan setelah proses selesai.</td></tr><tr><td>Ekspor file</td><td>Mengekspor <code>Markdown</code>, <code>PDF</code>, dan <code>Word</code>.</td></tr><tr><td>Batch packaging</td><td>Setelah mengenali beberapa file, hasilnya bisa diunduh sebagai satu paket.</td></tr></tbody></table><h2 id="konfigurasikan-layanan-ocr-lebih-dulu" tabindex="-1">Konfigurasikan Layanan OCR Lebih Dulu <a class="header-anchor" href="#konfigurasikan-layanan-ocr-lebih-dulu" aria-label="Permalink to &quot;Konfigurasikan Layanan OCR Lebih Dulu&quot;">​</a></h2><p>Buka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP geolocation and OCR" loading="lazy"></p><p>Isi credential untuk layanan yang ingin dipakai:</p><table tabindex="0"><thead><tr><th>Layanan</th><th>Yang Perlu Diisi</th><th>Cocok Untuk</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Pilihan pertama yang disarankan. Bagus untuk dokumen, gambar, tabel, dan layout campuran.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> dan <code>Azure Vision API Key</code></td><td>Berguna jika Anda sudah memakai layanan cloud Microsoft.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> hanya dipakai untuk query kuota.</td><td>Berguna jika Anda memakai layanan Google Cloud.</td></tr></tbody></table><p>Simpan setelah credential diisi.</p><p>Untuk uji awal, satu layanan saja sudah cukup. Anda tidak wajib mengonfigurasi ketiganya.</p><h2 id="setup-google-vision" tabindex="-1">Setup Google Vision <a class="header-anchor" href="#setup-google-vision" aria-label="Permalink to &quot;Setup Google Vision&quot;">​</a></h2><p>Setup Google terdiri dari dua bagian:</p><table tabindex="0"><thead><tr><th>Tujuan</th><th>Syarat</th></tr></thead><tbody><tr><td>Memakai OCR</td><td>Aktifkan <code>Cloud Vision API</code>, lalu buat <code>API Key</code>.</td></tr><tr><td>Query penggunaan</td><td>Buat service account, beri role <code>Monitoring Viewer</code>, lalu download service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Google API key and service account" loading="lazy"></p><h3 id="memakai-google-untuk-ocr" tabindex="-1">Memakai Google untuk OCR <a class="header-anchor" href="#memakai-google-untuk-ocr" aria-label="Permalink to &quot;Memakai Google untuk OCR&quot;">​</a></h3><ol><li>Buka Google Cloud Console.</li><li>Masuk ke <code>APIs &amp; Services</code>.</li><li>Buka <code>Library</code>, cari <code>Cloud Vision API</code>, lalu aktifkan.</li><li>Kembali ke <code>Credentials</code>.</li><li>Buat <code>API Key</code>.</li><li>Buka API Key tersebut dan salin nilainya.</li><li>Tempelkan ke <code>Google Vision API Key</code> di ImgBed.</li><li>Simpan.</li></ol><p>Setelah itu, Anda bisa memilih Google Vision di dialog OCR.</p><h3 id="query-penggunaan-google" tabindex="-1">Query Penggunaan Google <a class="header-anchor" href="#query-penggunaan-google" aria-label="Permalink to &quot;Query Penggunaan Google&quot;">​</a></h3><p>Query kuota tidak wajib untuk pengenalan teks.</p><p>Fitur ini hanya menampilkan perkiraan berapa banyak panggilan Google Vision yang dipakai dalam 30 hari terakhir.</p><ol><li>Di Google Cloud Console, buka <code>IAM &amp; Admin</code>.</li><li>Buka <code>Service Accounts</code>.</li><li>Buat service account, misalnya <code>vision-monitor</code>.</li><li>Berikan role <code>Monitoring Viewer</code>.</li><li>Buka detail service account dan buat key.</li><li>Pilih <code>JSON</code>.</li><li>Download file JSON yang dibuat.</li><li>Kembali ke ImgBed dan import ke service account <code>JSON</code> (opsional).</li><li>Setelah import berhasil, klik quota query.</li></ol><p>Setelah import, ImgBed menampilkan nama project pemilik service account tersebut. Saat query penggunaan, ImgBed membaca data monitoring Google dan menampilkan jumlah panggilan bulan ini.</p><p>Ringkasnya:</p><table tabindex="0"><thead><tr><th>Item</th><th>Fungsi</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Menjalankan OCR recognition.</td></tr><tr><td>Service account <code>JSON</code></td><td>Mengecek berapa banyak panggilan Google Vision yang sudah dipakai.</td></tr><tr><td>Role <code>Monitoring Viewer</code></td><td>Mengizinkan service account membaca data penggunaan.</td></tr></tbody></table><h2 id="mendapatkan-baidu-paddleocr-token" tabindex="-1">Mendapatkan Baidu PaddleOCR Token <a class="header-anchor" href="#mendapatkan-baidu-paddleocr-token" aria-label="Permalink to &quot;Mendapatkan Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR membutuhkan access token.</p><p><img src="'+t+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Buka jendela pemanggilan <code>API</code> di halaman Baidu PaddleOCR, klik untuk mendapatkan token, lalu salin token tersebut.</p><p>Kembali ke ImgBed, tempelkan ke <code>PaddleOCR Token</code>, lalu simpan.</p><h2 id="mulai-recognition" tabindex="-1">Mulai Recognition <a class="header-anchor" href="#mulai-recognition" aria-label="Permalink to &quot;Mulai Recognition&quot;">​</a></h2><p>Di File Management, pilih gambar atau screenshot dokumen, lalu klik <code>OCR</code>.</p><p><img src="'+n+'" alt="OCR recognition" loading="lazy"></p><p>Di dialog, pilih layanan recognition dan model.</p><p>Pilihan model PaddleOCR yang umum:</p><table tabindex="0"><thead><tr><th>Model</th><th>Cocok Untuk</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Default yang disarankan. Bagus untuk dokumen, tabel, rumus, cap, dan layout campuran.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Gambar sederhana, teks biasa, dan recognition ringan.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Multibahasa, gambar kompleks, dan konten seperti chart.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Halaman dokumen yang lebih kompleks dan pemulihan layout.</td></tr></tbody></table><p>Jika ragu, mulai dari <code>PP-StructureV3</code>.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opsi</th><th>Keterangan</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Gunakan jika gambar miring atau terputar.</td></tr><tr><td>Document flattening</td><td>Gunakan untuk dokumen yang difoto dengan lengkungan atau kemiringan.</td></tr><tr><td>Layout detection</td><td>Gunakan jika ingin mempertahankan struktur heading, paragraf, tabel, dan gambar.</td></tr><tr><td>Chart recognition</td><td>Gunakan jika gambar berisi chart atau struktur kompleks.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Membuat Markdown hasil ekspor lebih mudah dibaca.</td></tr></tbody></table><p>Untuk screenshot biasa, gunakan opsi seminimal mungkin. Untuk scan dokumen, aktifkan lebih banyak opsi terkait dokumen.</p><h2 id="melihat-hasil" tabindex="-1">Melihat Hasil <a class="header-anchor" href="#melihat-hasil" aria-label="Permalink to &quot;Melihat Hasil&quot;">​</a></h2><p>Setelah recognition selesai, dialog akan menampilkan hasilnya.</p><p>Anda bisa langsung menyalinnya atau memilih format ekspor.</p><p><img src="'+i+'" alt="PDF recognition" loading="lazy"></p><p>Untuk halaman dokumen, <code>PDF</code> hasil ekspor bisa mempertahankan tampilan halaman sambil membuat teks tetap searchable. Ini berguna untuk mengarsipkan scan dan mencari isi dokumen nanti.</p><h2 id="memilih-format-ekspor" tabindex="-1">Memilih Format Ekspor <a class="header-anchor" href="#memilih-format-ekspor" aria-label="Permalink to &quot;Memilih Format Ekspor&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Cocok Untuk</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Catatan, sistem dokumentasi, dan pengeditan lanjutan.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Menjaga tampilan halaman dan hasil scan dokumen.</td></tr><tr><td><code>Word (.docx)</code></td><td>Pengeditan layout, perubahan teks, dan handoff ke orang lain.</td></tr><tr><td>Export all</td><td>Menyimpan beberapa format dan gambar asli, cocok untuk arsip penting.</td></tr></tbody></table><p>Jika hanya membutuhkan teks, ekspor Markdown.</p><p>Jika perlu mempertahankan tampilan halaman, gunakan PDF atau Word.</p><h2 id="output-word" tabindex="-1">Output Word <a class="header-anchor" href="#output-word" aria-label="Permalink to &quot;Output Word&quot;">​</a></h2><p>Dokumen Word hasil ekspor bisa dibuka dan diedit dengan software office.</p><p><img src="'+d+`" alt="Word result" loading="lazy"></p><p>Beberapa dokumen menyertakan gambar, heading, dan paragraf yang dikenali di output Word.</p><p>Kualitas recognition bergantung pada kejernihan gambar asli, pilihan model, dan kompleksitas dokumen.</p><h2 id="jenis-file-yang-cocok-untuk-ocr" tabindex="-1">Jenis File yang Cocok untuk OCR <a class="header-anchor" href="#jenis-file-yang-cocok-untuk-ocr" aria-label="Permalink to &quot;Jenis File yang Cocok untuk OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Jenis File</th><th>Rekomendasi</th></tr></thead><tbody><tr><td>Screenshot jelas</td><td>Kenali langsung.</td></tr><tr><td>Scan</td><td>Utamakan <code>PP-StructureV3</code>.</td></tr><tr><td>Dokumen yang difoto</td><td>Aktifkan orientation correction dan document flattening.</td></tr><tr><td>Tabel, rumus, cap</td><td>Utamakan model structured.</td></tr><tr><td>Gambar teks pendek sederhana</td><td><code>PP-OCRv5</code> biasanya cukup.</td></tr></tbody></table><p>Gambar yang lebih jelas dengan teks yang lebih lurus biasanya menghasilkan recognition yang lebih baik.</p><h2 id="kasus-umum" tabindex="-1">Kasus Umum <a class="header-anchor" href="#kasus-umum" aria-label="Permalink to &quot;Kasus Umum&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kasus</th><th>Arti</th></tr></thead><tbody><tr><td>Recognition gagal</td><td>Periksa apakah token atau key layanan sudah disimpan.</td></tr><tr><td>Recognition lambat</td><td>Dokumen kompleks dan gambar besar membutuhkan waktu lebih lama.</td></tr><tr><td>Tabel tidak lengkap</td><td>Coba model structured.</td></tr><tr><td>Teks banyak salah</td><td>Blur, pantulan cahaya, dan kemiringan meningkatkan error. Coba gambar yang lebih jelas.</td></tr><tr><td>Output Word berisi banyak gambar</td><td>Model structured mungkin mempertahankan sebagian gambar yang dikenali. Ini normal.</td></tr></tbody></table><h3 id="query-kuota-google-gagal" tabindex="-1">Query Kuota Google Gagal <a class="header-anchor" href="#query-kuota-google-gagal" aria-label="Permalink to &quot;Query Kuota Google Gagal&quot;">​</a></h3><p>Periksa:</p><ol><li>Service account <code>JSON</code> sudah diimport.</li><li>Service account memiliki role <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> sudah diaktifkan untuk project tersebut.</li></ol><p>Jika hanya membutuhkan OCR dan tidak perlu query penggunaan, Anda bisa mengabaikan service account JSON dan cukup mengisi <code>Google Vision API Key</code>.</p><h2 id="alur-cepat" tabindex="-1">Alur Cepat <a class="header-anchor" href="#alur-cepat" aria-label="Permalink to &quot;Alur Cepat&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka System Settings</span></span>
<span class="line"><span>-&gt; Buka Other Settings</span></span>
<span class="line"><span>-&gt; Isi credential layanan OCR</span></span>
<span class="line"><span>-&gt; Simpan</span></span>
<span class="line"><span>-&gt; Kembali ke File Management</span></span>
<span class="line"><span>-&gt; Pilih file dan klik OCR</span></span>
<span class="line"><span>-&gt; Pilih model</span></span>
<span class="line"><span>-&gt; Tunggu recognition selesai</span></span>
<span class="line"><span>-&gt; Salin hasil atau ekspor Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const O=r(c,[["render",k]]);export{C as __pageData,O as default};
